+    type T;
+}
+
+impl<T: xr::ActionTy> ActionT<Actions> for T {
+    type T = xr::Action<T>;
+}
+impl<T: xr::ActionTy> ActionT<Bindings> for T {
+    type T = Vec<xr::Path>;
+}
+
+type Action<T, M> = <T as ActionT<M>>::T;
